using System;
using System.Collections.Generic;
using System.Linq;

namespace EduApp.Test3.Shared.Services
{
    public enum TaskCategory { MultipleChoice, Matching, TrueFalse, Ordering, Correction, Filling }

    public class SubItem { public string Id { get; set; } = ""; public string Text { get; set; } = ""; public string ExpectedAnswer { get; set; } = ""; public string UserAnswer { get; set; } = ""; }
    public class TaskOption { public string Label { get; set; } = ""; public string Text { get; set; } = ""; }

    public class CermatTask
    {
        public string TaskNumber { get; set; } = "";
        public string Instruction { get; set; } = "";
        public string TextBase { get; set; } = "";
        public TaskCategory Category { get; set; }
        public int MaxPoints { get; set; }
        public int EarnedPoints { get; set; }
        public bool IsEvaluated { get; set; }
        public string Explanation { get; set; } = "";

        public string ExpectedAnswer { get; set; } = "";
        public string UserAnswer { get; set; } = "";
        public List<SubItem> Items { get; set; } = new();
        public List<TaskOption> Options { get; set; } = new();
        public List<string> ExpectedSequence { get; set; } = new();
        public List<string> UserSequence { get; set; } = new();
        public int InputFieldsCount { get; set; }
        public string[] UserInputs { get; set; } = Array.Empty<string>();
        public string[] ExpectedInputs { get; set; } = Array.Empty<string>();
    }

    public class ExamRepository
    {
        public List<CermatTask> GetTest(string testId)
        {
            if (testId == "C9A-2025") return GetC9A2025();
            if (testId == "C9B-2025") return GetC9B2025();
            if (testId == "M25-PODZIM") return GetMaturita2025Podzim();
            return new List<CermatTask>();
        }

