                new CermatTask { TaskNumber = "4", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Která z následujících možností nejlépe vystihuje TEXT 1?", TextBase = textBlues, ExpectedAnswer = "A", Options = new() { new TaskOption { Label = "A", Text = "Jde o umělecký text, z jehož páté části vyplývá: Smutek nezažene skládání písní, ale až to, že se výsledek této tvůrčí činnosti podaří prodat či prosadit." }, new TaskOption { Label = "B", Text = "Jde o neumělecký text, z jehož páté části vyplývá: Smutek nezažene skládání písní, ale až to, že se výsledek této tvůrčí činnosti podaří prodat či prosadit." }, new TaskOption { Label = "C", Text = "Jde o umělecký text, z jehož páté části vyplývá: Smutek zmizí díky skládání písní bez ohledu na to, zda se podaří výsledek této tvůrčí činnosti prodat či prosadit." }, new TaskOption { Label = "D", Text = "Jde o neumělecký text, z jehož páté části vyplývá: Smutek zmizí díky skládání písní bez ohledu na to, zda se podaří výsledek této tvůrčí činnosti prodat či prosadit." } }, Explanation = "Báseň je umělecký text a v páté sloce se jasně říká: 'smutek ho však nepřestane pod srdíčkem bodat, dokud se mu nepodaří aspoň jednu prodat/prosadit'." },
                new CermatTask { TaskNumber = "5", Category = TaskCategory.Matching, MaxPoints = 3, Instruction = "Přiřaďte k jednotlivým tvrzením odpovídající souvětí (A-E).", TextBase = textSouveti, Items = new() { new SubItem { Id = "5.1", Text = "Toto souvětí se skládá ze dvou vět: ta druhá rozvíjí sloveso z první věty.", ExpectedAnswer = "E" }, new SubItem { Id = "5.2", Text = "Toto souvětí se skládá ze tří vět: ta třetí rozvíjí sloveso z druhé věty.", ExpectedAnswer = "B" }, new SubItem { Id = "5.3", Text = "Toto souvětí se skládá ze tří vět: ta třetí rozvíjí podstatné jméno z druhé věty.", ExpectedAnswer = "D" } }, Options = new() { new TaskOption { Label = "A", Text = "Věta A" }, new TaskOption { Label = "B", Text = "Věta B" }, new TaskOption { Label = "C", Text = "Věta C" }, new TaskOption { Label = "D", Text = "Věta D" }, new TaskOption { Label = "E", Text = "Věta E" } }, Explanation = "5.1 = E (Rozhodne (co?), jestli...). 5.2 = B (Snažila se mu vysvětlit (co?), proč ho opustila). 5.3 = D (Zdál se jí sen (jaký sen?), že padá)." },
                new CermatTask { TaskNumber = "6", Category = TaskCategory.Correction, MaxPoints = 3, Instruction = "Vypište z výchozího textu tři slova, z nichž každé obsahuje jak předponu o-, tak kořen složený ze tří hlásek.", TextBase = "okurkový, okradený, omrzlý, ohrožený, očarovaný, okamžitý, obezřetný, okřídlený, otlačený, odeslaný, olejový, opečený", InputFieldsCount = 3, UserInputs = new string[] { "", "", "" }, ExpectedSequence = new() { "očarovaný", "omrzlý", "opečený" }, Explanation = "očarovaný (o-čar-ova-ný, kořen čar = 3 hlásky), omrzlý (o-mrz-l-ý, kořen mrz = 3 hlásky), opečený (o-peč-en-ý, kořen peč = 3 hlásky)." },
                new CermatTask { TaskNumber = "7", Category = TaskCategory.TrueFalse, MaxPoints = 2, Instruction = "Rozhodněte o každém z následujících tvrzení, zda jednoznačně vyplývá z výchozího textu.", TextBase = textPontDuGard, Items = new() { new SubItem { Id = "7.1", Text = "Počátečním bodem celého akvaduktu, jehož prostřednictvím bylo město Nîmes zásobováno vodou, byl Pont du Gard.", ExpectedAnswer = "NE" }, new SubItem { Id = "7.2", Text = "V době, kdy oblast na jihu Francie patřila Římanům, bylo pomocí akvaduktu denně přivedeno do města Nîmes přibližně 400 litrů vody.", ExpectedAnswer = "NE" }, new SubItem { Id = "7.3", Text = "Pokud člověk půjde severovýchodním směrem od Pont du Gard, dostane se po zhruba 25 kilometrech do francouzského města Nîmes.", ExpectedAnswer = "NE" }, new SubItem { Id = "7.4", Text = "Podle mnohých zdrojů byl Pont du Gard postaven v 1. století př. n. l., podle některých historiků ale tento most vznikl až ve století následujícím.", ExpectedAnswer = "ANO" } }, Explanation = "7.1: Text říká, že byl jen 'součástí', nikoliv počátečním bodem. 7.2: Těch 400 litrů bylo *na každého obyvatele*, ne celkově do města. 7.3: Pont du Gard leží severovýchodně OD města, takže do města se musí jít na jihozápad." },
                new CermatTask { TaskNumber = "8", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení je pravdivé? (Posuzujte význam užitý ve třetí části textu).", TextBase = textPontDuGard, ExpectedAnswer = "C", Options = new() { new TaskOption { Label = "A", Text = "Výraz památka je významově nadřazený výrazu Pont du Gard, nikoli však výrazu Eiffelova věž." }, new TaskOption { Label = "B", Text = "Výraz památka je významově nadřazený výrazu Eiffelova věž, nikoli však výrazu Pont du Gard." }, new TaskOption { Label = "C", Text = "Výraz Pont du Gard je významově podřazený výrazu památka a výraz památka je významově nadřazený výrazu Eiffelova věž." }, new TaskOption { Label = "D", Text = "Výraz Pont du Gard je významově podřazený výrazu Eiffelova věž a výraz Eiffelova věž je významově podřazený výrazu památka." } }, Explanation = "Pont du Gard i Eiffelova věž jsou konkrétní památky. Slovo 'památka' je oběma těmto pojmům významově nadřazené." },
                new CermatTask { TaskNumber = "9", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Informace č. 1: Kusy kamenů vyčnívající z oblouků byly využívány při údržbě. Informace č. 2: Římské akvadukty měly pozitivní vliv na hygienické podmínky.", TextBase = textPontDuGard, ExpectedAnswer = "C", Options = new() { new TaskOption { Label = "A", Text = "Každá z těchto informací je ve výchozím textu předkládána jako zcela jistá." }, new TaskOption { Label = "B", Text = "Žádná z těchto informací není ve výchozím textu předkládána jako zcela jistá." }, new TaskOption { Label = "C", Text = "Na rozdíl od informace č. 1 je informace č. 2 ve výchozím textu předkládána jako zcela jistá." }, new TaskOption { Label = "D", Text = "Na rozdíl od informace č. 2 je informace č. 1 ve výchozím textu předkládána jako zcela jistá." } }, Explanation = "O účelu kamenů se píše 'nejspíš však byly důležité' a 'K výčnělkům se patrně upevňovalo...', takže to jisté není. O hygieně text říká jasně 'tedy mj. zlepšily hygienické podmínky' (to je předkládáno jako fakt)." },
                new CermatTask { TaskNumber = "10", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení o zájmenu 'které' tučně vyznačeném v textu je pravdivé?", TextBase = textPontDuGard, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "Ze samotného tvaru které je naprosto zřejmé, že toto zájmeno odkazuje ke slovu množství - smysl sdělení ani tvar slovesa muset není nutné posuzovat." }, new TaskOption { Label = "B", Text = "Ze samotného tvaru které je naprosto zřejmé, že toto zájmeno odkazuje ke slovu usazeniny - smysl sdělení ani tvar slovesa muset není nutné posuzovat." }, new TaskOption { Label = "C", Text = "Abychom mohli určit slovo, k němuž toto zájmeno odkazuje, je nutné posoudit i tvar slovesa muset - teprve poté bude zřejmé, že odkazuje ke slovu množství." }, new TaskOption { Label = "D", Text = "Abychom mohli určit slovo, k němuž toto zájmeno odkazuje, je nutné posoudit i tvar slovesa muset - teprve poté bude zřejmé, že odkazuje ke slovu usazeniny." } }, Explanation = "Tvar 'které' se může vázat jak na 'množství', tak na 'usazeniny'. Tvar přísudku 'musely' (s tvrdým y) prozrazuje, že podmět je v rodě ženském (usazeniny), nikoli středním (množství)." },
                new CermatTask { TaskNumber = "11", Category = TaskCategory.Correction, MaxPoints = 3, Instruction = "Vypište z DRUHÉ ČÁSTI textu TŘI podstatná jména, která se ve všech pádech skloňují podle vzoru PÍSEŇ.", TextBase = textPontDuGard, InputFieldsCount = 3, UserInputs = new string[] { "", "", "" }, ExpectedSequence = new() { "stráních", "nádrže", "koupelí" }, Explanation = "Ta stráň (bez stráně, jako píseň), ta nádrž (bez nádrže), ta koupel (bez koupele)." },
                new CermatTask { TaskNumber = "12", Category = TaskCategory.TrueFalse, MaxPoints = 2, Instruction = "Rozhodněte o každém z následujících větných celků, zda je zapsán pravopisně SPRÁVNĚ.", Items = new() { new SubItem { Id = "12.1", Text = "Jeho poměrně osobitý humor ji při prvním setkání skutečně okouzlil.", ExpectedAnswer = "ANO" }, new SubItem { Id = "12.2", Text = "Vzpomínkou na čas strávený s dědou je herbář s vylisovanými pomněnkami.", ExpectedAnswer = "ANO" }, new SubItem { Id = "12.3", Text = "Bloudil jsem tím cizým nevlídným městem snad půl dne, než jsem konečně našel ubytovnu.", ExpectedAnswer = "NE" }, new SubItem { Id = "12.4", Text = "Na displeji se zobrazily desítky nepřijatých hovorů, které přišly z neznámého telefonního čísla.", ExpectedAnswer = "ANO" } }, Explanation = "V bodě 12.3 je chyba: přídavné jméno 'cizí' se skloňuje podle vzoru jarní, má být tedy s měkkým i (cizím městem)." },
                new CermatTask { TaskNumber = "13", Category = TaskCategory.Filling, MaxPoints = 2, Instruction = "Napište náležitý spisovný tvar slov 'zodpovědný' a 'trvající' do textu.", TextBase = "Dokumenty jsem poslala na e-mailovou adresu pracovníka <b>[ 1 ]</b> za organizaci výběrového řízení. Ihned po pohovoru, <b>[ 2 ]</b> necelou hodinu, jsem se dozvěděla, že jsem byla vybrána.", InputFieldsCount = 2, UserInputs = new[] {"", ""}, ExpectedInputs = new[] {"zodpovědného", "trvajícím"}, Explanation = "1. Pracovníka (koho, čeho) zodpovědného. 2. Po pohovoru (kom, čem - 6. pád) trvajícím." },
                new CermatTask { TaskNumber = "14", Category = TaskCategory.Ordering, MaxPoints = 3, Instruction = "Seřaďte jednotlivé části textu (A-F) tak, aby byla dodržena textová návaznost.", ExpectedSequence = new() { "D", "A", "F", "B", "E", "C" }, Options = new() { new TaskOption { Label = "A", Text = "Právě v tomto zařízení má Britt-Marie pracovat. Jednoho lednového dne proto sedne do auta a dorazí do Borgu. Ve chvíli, kdy odbočuje na parkoviště, zaslechne z útrob vozu jakýsi zvuk." }, new TaskOption { Label = "B", Text = "Britt-Marie z něj vyděšeně vyskočí, protože logicky očekává, že auto vzplane. Ale nevzplane. Opodál se poklidně kutálí míč. Když balón zmizí za rohem budovy označené nápisem DŮM DĚTÍ A MLÁDEŽE, ozve se zadunění." }, new TaskOption { Label = "C", Text = "Úplně nahoře stojí „jet do Borgu“. Tenhle bod si odškrtne. Další položka zní „vyzvednout klíče na poště“. Vytáhne mobil a poprvé v životě ho použije." }, new TaskOption { Label = "D", Text = "Borg je vesnice u silnice. To je vlastně to nejhezčí, co se o Borgu dá říct. Je tu zrušené fotbalové hřiště, zrušená škola, zrušená lékárna a zrušené potraviny. Funguje tady dům dětí a mládeže, ale to jen proto, že ho zrušit ještě nestihli." }, new TaskOption { Label = "E", Text = "Zdálky to zní, jako kdyby někdo nacpal do sušičky kamení. Není to sice příliš pravděpodobné, ale Britt-Marie už zažila leccos. Sedne si na lavičku a roztřeseně vyndá z kabelky seznam." }, new TaskOption { Label = "F", Text = "Stižena adekvátní panikou, Britt-Marie pustí spojku i brzdu. Auto zakašle, jako by se něčeho leklo, když se zrovna ládovalo popcornem. Po několika dramatických smycích na zledovatělém povrchu konečně s rachotem zastaví." } }, Explanation = "Představení Borgu (D) -> Příjezd Britt-Marie (A) -> Zastavení auta (F) -> Vyskočení z auta a míč (B) -> Zvuk a usednutí na lavičku (E) -> Odškrtnutí bodu (C)." },
                new CermatTask { TaskNumber = "15", Category = TaskCategory.Correction, MaxPoints = 4, Instruction = "Najděte ve výchozím textu ČTYŘI slova, která jsou zapsána s pravopisnou chybou, a napište je SPRÁVNĚ.", TextBase = textJunior, InputFieldsCount = 4, UserInputs = new string[] { "", "", "", "" }, ExpectedSequence = new() { "nazývané", "zpřístupní", "trámy", "zmíněná" }, Explanation = "nazývané (vyjmenované slovo), zpřístupní (předpona z- pro změnu stavu), trámy (tvrdé y, vzor hrad), zmíněná (od zmínit - pouze jedno n)." },
                new CermatTask { TaskNumber = "16", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících slovních hodnocení nejlépe odpovídá textu o výrobě krmítka?", TextBase = textKrmitko, ExpectedAnswer = "C", Options = new() { new TaskOption { Label = "A", Text = "Snažil ses splnit zadaný úkol, tj. napsat popis pracovního postupu. Jednotlivé kroky na sebe logicky navazují, příště ale více promysli jazykové prostředky - v tomto typu textu není vhodné používat např. slovesa v 1. osobě čísla množného." }, new TaskOption { Label = "B", Text = "Zadaný úkol, tj. napsat subjektivně zabarvený popis předmětu, jsi splnil. Jednotlivé informace jsou logicky řazeny, příště ale více promysli jazykové prostředky - v tomto typu textu není vhodné používat např. slovesa v 1. osobě čísla množného." }, new TaskOption { Label = "C", Text = "Snažil ses splnit zadaný úkol, tj. napsat popis pracovního postupu. Vhodně jsi použil některé jazykové prostředky, např. slovesa v 1. osobě čísla množného. Příště ale více promysli popis jednotlivých kroků a jejich návaznost, protože v této oblasti tvůj text vykazuje nedostatky." }, new TaskOption { Label = "D", Text = "Zadaný úkol, tj. napsat subjektivně zabarvený popis předmětu, jsi splnil. Vhodně jsi použil některé jazykové prostředky, např. slovesa v 1. osobě čísla množného. Příště ale více promysli popis předmětu a řazení jednotlivých informací, protože v této oblasti tvůj text vykazuje nedostatky." } }, Explanation = "Je to popis pracovního postupu, slovesa v 1. os. množného čísla se zde běžně užívají, ale text má mezery v návaznosti postupu (dírky v miskách, pak svázání a náhle protahování pátou dírkou bez předchozího uvedení vrtání páté dírky)." },
                new CermatTask { TaskNumber = "17", Category = TaskCategory.TrueFalse, MaxPoints = 2, Instruction = "Rozhodněte o každém z tvrzení, zda jednoznačně vyplývá z TEXTU 1 (Kód horečky).", TextBase = textLeavitt, Items = new() { new SubItem { Id = "17.1", Text = "Doktor Leavitt si nahlas opakoval jednu větu, aby se uklidnil během nečekaného rozruchu na chodbě.", ExpectedAnswer = "NE" }, new SubItem { Id = "17.2", Text = "Těsně před tím, než omdlel, se Minho chystal Thomasovi prozradit, co přesně mu v nemocnici voperovali do hlavy.", ExpectedAnswer = "NE" }, new SubItem { Id = "17.3", Text = "Pacient s obvázanou hlavou reagoval křikem na anestezii, která mu byla aplikována v přítomnosti doktora Leavitta.", ExpectedAnswer = "NE" }, new SubItem { Id = "17.4", Text = "K prvnímu setkání Thomase a doktora Leavitta došlo před 8. hodinou ranní, a to tentýž den, kdy byl Thomas poprvé v devátém patře.", ExpectedAnswer = "ANO" } }, Explanation = "17.1: Větu říkal pro Thomase. 17.2: Minho říkal, že dělají 'jakoby nic, ale jsou banda prolhaných', nikoliv že mu prozradí co přesně mu voperovali. 17.3: Křičel předtím, než mu sestřička něco píchla na chodbě. 17.4: Správně, doktor zaťukal před osmou ranní ('Za půl hodiny - přesně v osm...') a hned v osm jeli do 9. patra." },
                new CermatTask { TaskNumber = "18", Category = TaskCategory.Filling, MaxPoints = 2, Instruction = "Vypište z podtržených úseků větné členy.", TextBase = textLeavitt, InputFieldsCount = 2, UserInputs = new[] {"", ""}, ExpectedInputs = new[] {"za nimi", "monitorů"}, Explanation = "18.1: Příslovečné určení místa (Kde stojí? za nimi). 18.2: Přívlastek neshodný (Jaká světla? monitorů)." },
                new CermatTask { TaskNumber = "19", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Co patří na vynechaná místa (*****) v TEXTU 1? (Řešte na základě TEXTU 2.)", TextBase = textLeavitt, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "Na každé z těchto míst patří jakoby." }, new TaskOption { Label = "B", Text = "Na každé z těchto míst patří jako by." }, new TaskOption { Label = "C", Text = "Na místo z první části textu patří jakoby, na místo ze čtvrté části textu patří jako by." }, new TaskOption { Label = "D", Text = "Na místo z první části textu patří jako by, na místo ze čtvrté části textu patří jakoby." } }, Explanation = "1. 'jeho nálada jako by se odrážela' (by je součástí podmiňovacího způsobu). 4. 'dělají jakoby nic' (jedno slovo, není to podmiňovací způsob)." },
                new CermatTask { TaskNumber = "20", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení o třetí části TEXTU 1 je pravdivé?", TextBase = textLeavitt, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "V této části promlouvá jak v přímé, tak v nepřímé řeči Thomas." }, new TaskOption { Label = "B", Text = "V této části promlouvá jak v přímé, tak v nepřímé řeči jiná postava než Thomas." }, new TaskOption { Label = "C", Text = "V této části promlouvá v přímé řeči nejspíše někdo jiný než Thomas, další postava něco sděluje v nepřímé řeči." }, new TaskOption { Label = "D", Text = "V této části promlouvá v přímé řeči nejspíše někdo jiný než Thomas, žádná z postav nic nesděluje v nepřímé řeči." } }, Explanation = "Je tam pouze 'Minho, stůj!', což pravděpodobně křičely sestry. Nikdo zde nic nesděluje nepřímou řečí." },
                new CermatTask { TaskNumber = "21", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Ve které z možností je uvedena dvojice slov, jež jsou v kontextu TEXTU 1 ANTONYMY?", TextBase = textLeavitt, ExpectedAnswer = "A", Options = new() { new TaskOption { Label = "A", Text = "zachmuřený - usměvavý" }, new TaskOption { Label = "B", Text = "narušení - normální" }, new TaskOption { Label = "C", Text = "mimochodem - záměrně" }, new TaskOption { Label = "D", Text = "zavedl - odvedl" } }, Explanation = "Zachmuřený (smutný, zamračený) je přesným opakem slova usměvavý." },
                new CermatTask { TaskNumber = "22", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z následujících tvrzení o tučně vyznačených slovech v TEXTU 1 je pravdivé?", TextBase = textLeavitt, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "Slovo „jednotce“ je v textu číslovka." }, new TaskOption { Label = "B", Text = "Slovo „ticho“ je v textu příslovce." }, new TaskOption { Label = "C", Text = "Slovo „je“ je v textu sloveso." }, new TaskOption { Label = "D", Text = "Slovo „tu“ je v textu zájmeno." } }, Explanation = "Slovo 'tu' ve spojení 'tu větu' je ukazovací zájmeno. (Jednotka je podstatné jméno, ticho zde také, je je osobní zájmeno)." },
                new CermatTask { TaskNumber = "23", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Ve kterém z následujících souvětí NENÍ správně zapsána interpunkce?", ExpectedAnswer = "A", Options = new() { new TaskOption { Label = "A", Text = "Nikdy nevíte, kdy budete něčí pomoc, potřebovat zrovna vy." }, new TaskOption { Label = "B", Text = "Spatříte-li člověka, který se nehýbe, okamžitě přivolejte pomoc." }, new TaskOption { Label = "C", Text = "Ležící člověk, který se stlačení hrudníku nebrání, vaši pomoc potřebuje." }, new TaskOption { Label = "D", Text = "Mějte na paměti, že poskytnout první pomoc není tak těžké, jak se možná zdá." } }, Explanation = "Ve větě A je čárka uprostřed věty vedlejší před slovem 'potřebovat' zcela navíc a odděluje předmět od přísudku." },
