                new CermatTask { TaskNumber = "3", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které tvrzení nejlépe vystihuje tučné verše z TEXTU 1?", TextBase = textPoetry, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "Pomocí personifikace je vyjádřeno, že nelze zveřejnit jakoukoli poezii." }, new TaskOption { Label = "B", Text = "Pomocí personifikace je vyjádřeno, že nemá smysl psát bez možnosti uveřejnit." }, new TaskOption { Label = "C", Text = "Je užito ustálené slovní spojení a vyzněním je: Nelze zveřejnit poezii." }, new TaskOption { Label = "D", Text = "Je užito ustálené slovní spojení a vyzněním je: Nemá smysl psát bez úmyslu uveřejnit." } }, Explanation = "'Psát do šuplíka' je frazém (ustálené slovní spojení), znamenající tvořit něco, co nikdo neuvidí." },
