                new CermatTask { TaskNumber = "5", Category = TaskCategory.Matching, MaxPoints = 3, Instruction = "Přiřaďte k jednotlivým větám odpovídající tvrzení.", Items = new() { new SubItem { Id = "5.1", Text = "Ze sousední ordinace se několikrát za sebou ozvalo dost hlasité ouvej.", ExpectedAnswer = "D" }, new SubItem { Id = "5.2", Text = "Vzhledem k okolnostem všichni nakonec vyhověli návrhu uzavřít příměří.", ExpectedAnswer = "A" }, new SubItem { Id = "5.3", Text = "Poslouchat jeho lži nebylo vůbec snadné.", ExpectedAnswer = "C" } }, Options = new() { new TaskOption { Label = "A", Text = "Podmět = zájmeno, Přísudek = slovesný" }, new TaskOption { Label = "B", Text = "Podmět = infinitiv, Přísudek = slovesný" }, new TaskOption { Label = "C", Text = "Podmět = infinitiv, Přísudek = jmenný se sponou" }, new TaskOption { Label = "D", Text = "Podmět = neohebný slovní druh, Přísudek = slovesný" }, new TaskOption { Label = "E", Text = "Podmět = neohebný slovní druh, Přísudek = jmenný se sponou" } }, Explanation = "5.1: Ouvej (citoslovce = neohebný) ozvalo se (slovesný). 5.2: Všichni (zájmeno) vyhověli (slovesný). 5.3: Poslouchat (infinitiv) nebylo snadné (jmenný se sponou)." },
                new CermatTask { TaskNumber = "6", Category = TaskCategory.Correction, MaxPoints = 3, Instruction = "Vypište z textu tři slova, z nichž každé obsahuje DVA KOŘENY.", TextBase = "pravěký, bezprostředně, nadpozemský, nedochvilný, pochopitelně, mnohočetný, obdobně, bohudík, domorodý, dotazník, předpokládaný, nejvybranější.", InputFieldsCount = 3, UserInputs = new string[] { "", "", "" }, ExpectedSequence = new() { "domorodý", "mnohočetný", "bohudík" }, Explanation = "Slova složená ze dvou kořenů: dom-o-rod-ý, mnoh-o-čet-ný, boh-u-dík." },
                new CermatTask { TaskNumber = "7", Category = TaskCategory.TrueFalse, MaxPoints = 2, Instruction = "Rozhodněte o každém z následujících tvrzení, zda jednoznačně vyplývá z výchozího textu o zvonech.", TextBase = textZvony, Items = new() { new SubItem { Id = "7.1", Text = "Náklady na výrobu zvonu činily celkem 12,5 milionu Kč.", ExpectedAnswer = "NE" }, new SubItem { Id = "7.2", Text = "Teplota roztavené zvonoviny je vyšší než 1 000 °C.", ExpectedAnswer = "ANO" }, new SubItem { Id = "7.3", Text = "Více než 90 % všech zvonů, které nacisté zabavili, pocházelo z protektorátu.", ExpectedAnswer = "NE" }, new SubItem { Id = "7.4", Text = "Výzdoba byla vytvořena podle kopie návrhu českých zvonařů.", ExpectedAnswer = "NE" } }, Explanation = "7.1: Bylo vybráno 12.5M, nevíme jestli to byly celé náklady. 7.3: 90% zdejších zvonů, nikoli 90% všech zabavených v celé říši." },
                new CermatTask { TaskNumber = "8", Category = TaskCategory.Correction, MaxPoints = 3, Instruction = "Vypište z první části textu (odstavce 1 a 2) 3 podstatná jména, která se skloňují podle vzoru MUŽ.", TextBase = textZvony, InputFieldsCount = 3, UserInputs = new string[] { "", "", "" }, ExpectedSequence = new() { "zloději", "příznivců", "zvonaře" }, Explanation = "Ten zloděj (bez zloděje jako muž bez muže). Ten příznivec (bez příznivce). Ten zvonař (bez zvonaře)." },
                new CermatTask { TaskNumber = "9", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Která z následujících informací je v textu o zvonech předkládána jako NEJMÉNĚ JISTÁ?", TextBase = textZvony, ExpectedAnswer = "C", Options = new() { new TaskOption { Label = "A", Text = "odlévání zvonu je dost rizikové" }, new TaskOption { Label = "B", Text = "zvon byl odlit v červnu 2022" }, new TaskOption { Label = "C", Text = "odlití trvalo pouhých 6 minut" }, new TaskOption { Label = "D", Text = "kdysi se nepovedlo velké zvony odlít napoprvé" } }, Explanation = "V textu je u 6 minut použito slovní spojení 'prý odlit', což vyjadřuje nejistotu/neověřenou informaci." },
                new CermatTask { TaskNumber = "10", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Ke kterému slovu odkazuje tučně vyznačené zájmeno 'jenž' v textu o zvonech?", TextBase = textZvony, ExpectedAnswer = "C", Options = new() { new TaskOption { Label = "A", Text = "Gramaticky i smyslem k oběma (zvon, název)." }, new TaskOption { Label = "B", Text = "Gramaticky jen k název, smyslem k oběma." }, new TaskOption { Label = "C", Text = "Gramaticky k oběma, smyslem jen ke zvon." }, new TaskOption { Label = "D", Text = "Gramaticky k oběma, smyslem jen k název." } }, Explanation = "Tvar 'jenž' může gramaticky navazovat na 'zvon' i 'názvem' (rod muž. neživ.). Významově ale zvon připomíná bratry, nikoli jeho název." },
                new CermatTask { TaskNumber = "11", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Kde je vztah nejpodobnější vztahu: ZVONOVINA – ZVON?", ExpectedAnswer = "A", Options = new() { new TaskOption { Label = "A", Text = "sníh - iglú" }, new TaskOption { Label = "B", Text = "sopka - láva" }, new TaskOption { Label = "C", Text = "poleva - čokoláda" }, new TaskOption { Label = "D", Text = "zmrzlina - kornout" } }, Explanation = "Zvonovina je materiál, ze kterého se vyrábí zvon. Sníh je materiál, ze kterého se staví iglú." },
                new CermatTask { TaskNumber = "12", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Doplňte do věty: *****, která nejčastěji zobrazují momentky ze života obyčejných lidí, toto prestižní ocenění patří právem.", ExpectedAnswer = "A", Options = new() { new TaskOption { Label = "A", Text = "Autorce unikátních výtvarných děl" }, new TaskOption { Label = "B", Text = "Autorka unikátních výtvarných děl" }, new TaskOption { Label = "C", Text = "Autorce svými unikátními výtvarnými díly" }, new TaskOption { Label = "D", Text = "Autorka svými unikátními výtvarnými díly" } }, Explanation = "Vložená věta vedlejší 'která zobrazují' se musí vztahovat k dílům (díla, která zobrazují). Patří to (komu?) autorce děl." },
                new CermatTask { TaskNumber = "13", Category = TaskCategory.TrueFalse, MaxPoints = 2, Instruction = "Rozhodněte, zda jsou souvětí zapsána PRAVOPISNĚ správně.", Items = new() { new SubItem { Id = "13.1", Text = "Kadeřnice měla natolik nabitý diář, že mi první volný termín nabídla až za tři měsíce.", ExpectedAnswer = "ANO" }, new SubItem { Id = "13.2", Text = "Papírový drak, kterého si děti včera pouštěly, omylem skončil na nejvyšší větvi nedalekého stromu.", ExpectedAnswer = "ANO" }, new SubItem { Id = "13.3", Text = "Každou žádost podanou písemně je nutné opatřit podpisem, jehož pravost musí být potvrzena notářem.", ExpectedAnswer = "ANO" }, new SubItem { Id = "13.4", Text = "Nedomykavost srdečních chlopní lze účinně odstranit operací, která se na našem specializovaném pracovišti provádí již řadu let.", ExpectedAnswer = "ANO" } }, Explanation = "Všechna souvětí jsou bez gramatických chyb (i/y, mě/mně, interpunkce)." },
                new CermatTask { TaskNumber = "14", Category = TaskCategory.Filling, MaxPoints = 2, Instruction = "Doplňte náležitý spisovný tvar slov do textu.", TextBase = "Po (oba) <b>[ 1 ]</b> stranách ulice se válely odpadky. Naši pomoc, (nabízený) <b>[ 2 ]</b> opakovaně, ale soused odmítl.", InputFieldsCount = 2, UserInputs = new[] {"", ""}, ExpectedInputs = new[] {"obou", "nabízenou"}, Explanation = "14.1: Po obou (6. pád, rod ženský). 14.2: pomoc (4. pád, rod ženský -> nabízenou)." },
                new CermatTask { TaskNumber = "15", Category = TaskCategory.Ordering, MaxPoints = 3, Instruction = "Seřaďte části textu (A–F) tak, aby byla dodržena textová návaznost.", ExpectedSequence = new() { "E", "B", "D", "C", "A", "F" }, Options = new() { new TaskOption { Label = "A", Text = "Věnovala dvacet minut tomu, aby odpověděla tak, jak Borgov nečekal. Další hodiny se nedívala na něj ani na diváky, dokonce ani na rozhodčího ne.Sledovala pouze ztělesněné hrozby – jezdce, střelce, věž, pěšce, krále a dámu." }, new TaskOption { Label = "B", Text = "Už seděl u stolu a čekal na ni. Při tom pohledu se mladé ženě zastavilo srdce i dech: ta nehybná postava, upřeně pozorující černé figurky v základním postavení, nejevila žádné známky slabosti." }, new TaskOption { Label = "C", Text = "Zahájila pěšcem na d4 a soustředila se na šachovnici. V hlavě měla jasno a tahy znala. Sedmým tahem ji ovšem Borgov překvapil." }, new TaskOption { Label = "D", Text = "Beth pomalu došla k šachovnici a usadila se k bílým. Z obecenstva se ozval tichý potlesk. Rozhodčí zmáčkl knoflík a Beth uslyšela, jak se jí rozběhly hodiny" }, new TaskOption { Label = "E", Text = "Když Beth přecházela jeviště, všimla si, že hlediště je úplně napěchované. Pak se ten obrovský dav ztišil a ona se poprvé podívala na Borgova. Měla z něj hrůzu od té doby, co ho spatřila před gorilí klecí během turnaje v Mexiku." }, new TaskOption { Label = "F", Text = "Když Borgovovi zbývalo posledních sedm minut, rozhodl se, že nechá svůj tah zapečetit. Pokračovat v rozehrané partii se bude následující den ráno." } }, Explanation = "Správné pořadí: Příchod (E) -> Pohled na Borgova u stolu (B) -> Usednutí a start hodin (D) -> Zahájení partie (C) -> Průběh partie (A) -> Konec a zapečetění tahu (F)." },
                new CermatTask { TaskNumber = "16", Category = TaskCategory.Correction, MaxPoints = 4, Instruction = "Najděte 4 slova zapsaná s pravopisnou chybou a napište je SPRÁVNĚ.", TextBase = textPisek, InputFieldsCount = 4, UserInputs = new string[] { "", "", "", "" }, ExpectedSequence = new() { "kamenný", "zprostředkují", "včelí", "náramně" }, Explanation = "Kamenný (kamen+ný), zprostředkují (předpona z-), včelí (vzor jarní), náramně (náramný+ně)." },
                new CermatTask { TaskNumber = "17", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Které z hodnocení nejlépe odpovídá textu o tanci Hula?", TextBase = textTanec, ExpectedAnswer = "B", Options = new() { new TaskOption { Label = "A", Text = "Úkolem bylo napsat reklamní text doporučující plážový hotel a toto zadání jsi splnil. Dobře jsi rozčlenil text do odstavců, oceňuji i výběr jazykových prostředků a vysvětlení termínu a cappella. Titulek by ale mohl být poutavější." }, new TaskOption { Label = "B", Text = "Úkolem bylo napsat publicistický text o nějaké zahraniční tradici a toto zadání jsi splnil. Dobře jsi rozčlenil text do odstavců, oceňuji i výběr jazykových prostředků a vysvětlení termínu a cappella. Titulek by ale mohl být poutavější." }, new TaskOption { Label = "C", Text = "Úkolem bylo napsat reklamní text doporučující plážový hotel a toto zadání jsi splnil. Oceňuji výběr jazykových prostředků a poutavý titulek. Příště se ale více soustřeď na členění textu (poslední dva odstavce je potřeba spojit) a nepoužívej termíny (např. a cappella) – ty totiž do tohoto typu textu nepatří." }, new TaskOption { Label = "D", Text = "Úkolem bylo napsat publicistický text o nějaké zahraniční tradici a toto zadání jsi splnil. Oceňuji výběr jazykových prostředků a poutavý titulek. Příště se ale více soustřeď na členění textu (poslední dva odstavce je potřeba spojit) a nepoužívej termíny (např. a cappella) – ty totiž do tohoto typu textu nepatří." } }, Explanation = "Jde o publicistický (informační) text, neplní funkci čisté reklamy hotelu. Termíny jsou správně vysvětleny." },
                new CermatTask { TaskNumber = "18", Category = TaskCategory.TrueFalse, MaxPoints = 2, Instruction = "Vyplývá tvrzení jednoznačně z textu Stopařova průvodce?", TextBase = textStopar, Items = new() { new SubItem { Id = "18.1", Text = "Na kdysi funkčním záchodě, který se nacházel ve sklepě úřadu pro místní rozvoj, žil leopard.", ExpectedAnswer = "NE" }, new SubItem { Id = "18.2", Text = "Arthur se o stavbě dálničního obchvatu dozvěděl ve středu, tedy jiný den, než na jeho zahradu vjel buldozer.", ExpectedAnswer = "ANO" }, new SubItem { Id = "18.3", Text = "Navzdory předloženým argumentům Arthur odmítal vstát ze země, a tak se L. Prosser rozhodl, že ho nechá přejet buldozerem.", ExpectedAnswer = "NE" }, new SubItem { Id = "18.4", Text = "Zákonná lhůta, ve které člověk může podat námitku proti rozhodnutí úřadu pro místní rozvoj, činí podle L. Prossera tři čtvrtě roku.", ExpectedAnswer = "NE" } }, Explanation = "18.1: Byla tam jen cedule. 18.2: Ve čtvrtek ráno vzpomínal, že to zjistil 'včera' (středa). 18.4: Plány visely 3/4 roku, ale nevíme, jak dlouhá je samotná zákonná lhůta." },
                new CermatTask { TaskNumber = "19", Category = TaskCategory.Filling, MaxPoints = 2, Instruction = "Napište druh příslovečného určení pro uvedená slova z textu.", TextBase = "<b>[ 1 ]</b> KVŮLI STAVBĚ dálničního obchvatu... <b>[ 2 ]</b> ležet NAVĚKY.", InputFieldsCount = 2, UserInputs = new[] {"", ""}, ExpectedInputs = new[] {"příčiny/příčinné/důvodu/důvodové", "času/časové"}, Explanation = "1. Proč se rozčiloval? Kvůli stavbě -> PU příčiny/důvodu. 2. Jak dlouho tam bude ležet? Navěky -> PU času." },
                new CermatTask { TaskNumber = "20", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Která možnost vystihuje charakteristiku postav v textu Stopaře?", TextBase = textStopar, ExpectedAnswer = "D", Options = new() { new TaskOption { Label = "A", Text = "Vnější char. L. Prossera i Arthura. Vnitřní char. A (přímé pojmenování vlastností) je přítomna." }, new TaskOption { Label = "B", Text = "Vnější char. obou. Vnitřní char. A chybí." }, new TaskOption { Label = "C", Text = "Vnější char. pouze L. Prossera. Vnitřní char. A je přítomna." }, new TaskOption { Label = "D", Text = "Vnější char. pouze L. Prossera (čtyřicetiletý, obtloustlý). Vnitřní char. A chybí." } }, Explanation = "Vzhled Arthura není popsán. Nikdo v textu není přímo označen povahovým přídavným jménem (vnitřní A)." },
                new CermatTask { TaskNumber = "21", Category = TaskCategory.MultipleChoice, MaxPoints = 1, Instruction = "Co lze smysluplně doplnit na vynechané místo [ ***** ] v textu Stopaře?", TextBase = textStopar, ExpectedAnswer = "C", Options = new() { new TaskOption { Label = "A", Text = "Na toto místo lze doplnit jak úsek Vzápětí padla otázka: „A jestli se vám je podaří najít?“, tak úsek Vzápětí padla otázka, jestli se mu je podaří najít." }, new TaskOption { Label = "B", Text = "Na toto místo lze doplnit jak úsek Vzápětí padla otázka: „A jestli se vám je podaří najít?“, tak úsek Vzápětí padla otázka, jestli se jim je podaří najít." }, new TaskOption { Label = "C", Text = "Na toto místo lze doplnit jak úsek Vzápětí padla otázka: „A podařilo se vám je najít?“, tak úsek Vzápětí padla otázka, jestli se mu je podařilo najít." }, new TaskOption { Label = "D", Text = "Na toto místo lze doplnit jak úsek Vzápětí padla otázka: „A podařilo se vám je najít?“, tak úsek Vzápětí padla otázka, jestli se jim je podařilo najít." } }, Explanation = "V návaznosti 'Ale jo. Byly ve sklepě' dává smysl pouze otázka na to, zda je už našel." },
